/**
 * Unit Tests: Security Headers
 * Testa getSecurityHeaders, getCorsHeaders e isValidOrigin
 */

import { getSecurityHeaders, getCorsHeaders, isValidOrigin } from '@/lib/security/security-headers';

describe('Security Headers', () => {
  describe('getSecurityHeaders', () => {
    it('should return all standard security headers in production mode', () => {
      const headers = getSecurityHeaders(false);

      expect(headers['X-Content-Type-Options']).toBe('nosniff');
      expect(headers['X-Frame-Options']).toBe('SAMEORIGIN');
      expect(headers['Referrer-Policy']).toBe('strict-origin-when-cross-origin');
      expect(headers['Permissions-Policy']).toBe('camera=(), microphone=(), geolocation=()');
      expect(headers['Strict-Transport-Security']).toContain('max-age=');
    });

    it('should omit HSTS in dev mode', () => {
      const headers = getSecurityHeaders(true);

      expect(headers['Strict-Transport-Security']).toBeUndefined();
      expect(headers['X-Content-Type-Options']).toBe('nosniff');
      expect(headers['X-Frame-Options']).toBe('SAMEORIGIN');
    });

    it('should include HSTS with proper directives in production', () => {
      const headers = getSecurityHeaders(false);
      const hsts = headers['Strict-Transport-Security'];

      expect(hsts).toContain('max-age=');
      expect(hsts).toContain('includeSubDomains');
      expect(hsts).toContain('preload');
    });

    it('should return a plain object', () => {
      const headers = getSecurityHeaders();
      expect(typeof headers).toBe('object');
      expect(headers).not.toBeNull();
    });
  });

  describe('getCorsHeaders', () => {
    it('should return CORS headers with valid origin', () => {
      const headers = getCorsHeaders('https://cursostecno.com.br');

      expect(headers['Access-Control-Allow-Origin']).toBe('https://cursostecno.com.br');
      expect(headers['Access-Control-Allow-Methods']).toContain('GET');
      expect(headers['Access-Control-Allow-Methods']).toContain('POST');
      expect(headers['Access-Control-Allow-Headers']).toContain('Authorization');
      expect(headers['Access-Control-Allow-Credentials']).toBe('true');
    });

    it('should fallback to default origin for null origin', () => {
      const headers = getCorsHeaders(null);

      // When origin is null, isValidOrigin returns false, so it uses default
      expect(headers['Access-Control-Allow-Origin']).toBeTruthy();
      expect(headers['Access-Control-Allow-Origin']).not.toBe('*');
    });

    it('should fallback to default for invalid origin', () => {
      const headers = getCorsHeaders('https://evil.com');

      expect(headers['Access-Control-Allow-Origin']).not.toBe('https://evil.com');
    });

    it('should include all standard CORS methods', () => {
      const headers = getCorsHeaders('https://cursostecno.com.br');
      const methods = headers['Access-Control-Allow-Methods'];

      expect(methods).toContain('GET');
      expect(methods).toContain('POST');
      expect(methods).toContain('PUT');
      expect(methods).toContain('DELETE');
      expect(methods).toContain('OPTIONS');
    });
  });

  describe('isValidOrigin', () => {
    it('should return true for production domain', () => {
      expect(isValidOrigin('https://cursostecno.com.br')).toBe(true);
    });

    it('should return false for null', () => {
      expect(isValidOrigin(null)).toBe(false);
    });

    it('should return false for empty string', () => {
      expect(isValidOrigin('')).toBe(false);
    });

    it('should return false for unknown origin', () => {
      expect(isValidOrigin('https://malicious-site.com')).toBe(false);
    });

    it('should return false for invalid URL format', () => {
      expect(isValidOrigin('not-a-url')).toBe(false);
    });

    it('should return false for subdomain of allowed origin', () => {
      expect(isValidOrigin('https://sub.cursostecno.com.br')).toBe(false);
    });

    it('should return false for same domain but different protocol', () => {
      // http vs https
      expect(isValidOrigin('http://cursostecno.com.br')).toBe(false);
    });
  });
});
